import React from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { getEventById } from '../../data/events';
import { models } from '../../data/models';
import './EventDetail.css';

function EventDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const event = getEventById(id);

  if (!event) {
    return (
      <div className="container" style={{ padding: '80px 24px', textAlign: 'center' }}>
        <h2>Event not found</h2>
        <Link to="/events" className="btn-primary" style={{ marginTop: '20px' }}>Back to Events</Link>
      </div>
    );
  }

  const formattedDate = new Date(event.date).toLocaleDateString('en-IN', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  });

  const eventModels = models.filter((m) => event.models.includes(m.id));
  const isSoldOut = event.seatsLeft === 0;

  return (
    <div className="event-detail">
      {/* Hero banner */}
      <div
        className="event-detail__hero"
        style={{ backgroundImage: `url(${event.image})` }}
      >
        <div className="event-detail__hero-overlay">
          <div className="container">
            <button onClick={() => navigate(-1)} className="event-detail__back">← Back</button>
            <span className="badge badge-gold">{event.category}</span>
            <h1>{event.title}</h1>
            <div className="event-detail__hero-meta">
              <span>📅 {formattedDate} · {event.time}</span>
              <span>📍 {event.location}</span>
            </div>
          </div>
        </div>
      </div>

      <div className="container event-detail__body">
        {/* Left: details */}
        <div className="event-detail__main">
          <section>
            <h2>About This Event</h2>
            <p>{event.description}</p>
          </section>

          <section>
            <h2>Event Highlights</h2>
            <ul className="event-detail__highlights">
              {event.highlights.map((h, i) => (
                <li key={i}><span>✦</span> {h}</li>
              ))}
            </ul>
          </section>

          <section>
            <h2>Featured Models</h2>
            <div className="event-detail__models">
              {eventModels.map((m) => (
                <div key={m.id} className="event-detail__model-chip">
                  <img src={m.image} alt={m.name} />
                  <div>
                    <span className="event-detail__model-name">{m.name}</span>
                    <span className="event-detail__model-spec">{m.specialty}</span>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* Right: booking box */}
        <div className="event-detail__sidebar">
          <div className="booking-box">
            <div className="booking-box__price">
              <span className="booking-box__price-label">Price per ticket</span>
              <span className="booking-box__price-value">₹{event.price.toLocaleString('en-IN')}</span>
            </div>

            <div className="booking-box__info">
              <div className="booking-box__row">
                <span>Date</span>
                <span>{formattedDate}</span>
              </div>
              <div className="booking-box__row">
                <span>Time</span>
                <span>{event.time}</span>
              </div>
              <div className="booking-box__row">
                <span>Venue</span>
                <span>{event.location}</span>
              </div>
              <div className="booking-box__row">
                <span>Seats Left</span>
                <span className={event.seatsLeft <= 20 ? 'text-red' : 'text-green'}>
                  {isSoldOut ? 'Sold Out' : `${event.seatsLeft} remaining`}
                </span>
              </div>
            </div>

            {isSoldOut ? (
              <button className="btn-primary" disabled style={{ width: '100%', opacity: 0.6 }}>
                Sold Out
              </button>
            ) : (
              <Link
                to={`/booking/${event.id}`}
                className="btn-primary"
                style={{ width: '100%', textAlign: 'center', display: 'block' }}
              >
                Book My Seat Now
              </Link>
            )}
            <p className="booking-box__note">📧 Instant email confirmation upon booking</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EventDetail;
